        var liveStackMode = 'off';
        var liveStackRunning = false;
        var liveStackFrameCount = 0;
        var liveStackTargetFrames = 0;
        var liveStackInterval = null;

        function setLiveStackMode(mode) {
            liveStackMode = mode;
            // 更新按钮状态
            document.querySelectorAll('[data-stack]').forEach(function(btn) {
                btn.classList.remove('btn-primary');
                btn.classList.add('btn-secondary');
            });
            var activeBtn = document.querySelector('[data-stack="' + mode + '"]');
            if (activeBtn) {
                activeBtn.classList.remove('btn-secondary');
                activeBtn.classList.add('btn-primary');
            }

            // 更新状态显示
            var statusText = '叠加: ' + (mode === 'off' ? '关闭' : mode);
            document.getElementById('liveStackStatus').textContent = statusText;
        }

        function startLiveStack() {
            if (!window.connectedDevice || !window.connectedDevice.ip) {
                showToast('warning', '请先连接设备');
                return;
            }

            if (liveStackMode === 'off') {
                showToast('warning', '请先选择叠加档位');
                return;
            }

            var deviceIp = window.connectedDevice.ip;
            var hardwareMs = parseFloat(document.getElementById('hardwareExposureMs').value) || 100;

            // 根据档位计算目标曝光
            var exposureMap = {
                '2s': 2, '5s': 5, '10s': 10, '30s': 30
            };
            var targetExposure = parseFloat(exposureMap[liveStackMode]) || 2;

            // 启动 Live Stack
            apiPost('/api/v1/stack/start', {
                device_ip: deviceIp,
                target_exposure: targetExposure,
                hardware_exposure_ms: hardwareMs,
                mode: 'live'
            }).then(function(result) {
                if (result && result.success) {
                    liveStackRunning = true;
                    liveStackTargetFrames = result.target_frames;
                    liveStackFrameCount = 0;

                    showToast('success', 'Live Stack 已启动: ' + result.target_frames + '帧');

                    // 更新按钮状态
                    document.getElementById('btnLiveStackStart').disabled = true;
                    document.getElementById('btnLiveStackStop').disabled = false;
                    document.getElementById('btnLiveStackSave').disabled = true;

                    // 开始采集帧
                    liveStackInterval = setInterval(captureAndSendFrame, hardwareMs);
                } else {
                    showToast('error', result ? result.message : '启动失败');
                }
            }).catch(function(e) {
                showToast('error', '启动异常: ' + e.message);
            });
        }

        function captureAndSendFrame() {
            if (!liveStackRunning) return;

            // 从 Canvas 截图
            var canvas = document.querySelector('#divPlugin canvas');
            if (!canvas) {
                // 尝试其他方式
                canvas = document.getElementById('divPlugin').querySelector('canvas');
            }

            if (!canvas) {
                console.warn('[LiveStack] Canvas not found');
                return;
            }

            try {
                var imageData = canvas.toDataURL('image/jpeg', 0.85);

                // 发送到后端
                apiPost('/api/v1/stack/frame', {
                    device_ip: window.connectedDevice.ip,
                    frame_data: imageData
                }).then(function(result) {
                    if (result && result.success) {
                        liveStackFrameCount = result.frame_count;
                        var progress = Math.round(liveStackFrameCount / liveStackTargetFrames * 100);

                        // 更新状态
                        document.getElementById('liveStackStatus').textContent =
                            '叠加: ' + liveStackFrameCount + '/' + liveStackTargetFrames + ' (' + progress + '%)';

                        // 更新预览
                        if (result.preview_base64) {
                            // 可以显示预览(可选)
                        }

                        // 检查是否完成
                        if (liveStackFrameCount >= liveStackTargetFrames) {
                            stopLiveStack();
                            showToast('success', '叠加完成');
                            document.getElementById('btnLiveStackSave').disabled = false;
                        }
                    }
                }).catch(function(e) {
                    console.warn('[LiveStack] Frame send error:', e.message);
                });
            } catch (e) {
                console.warn('[LiveStack] Capture error:', e.message);
            }
        }

        function stopLiveStack() {
            liveStackRunning = false;

            if (liveStackInterval) {
                clearInterval(liveStackInterval);
                liveStackInterval = null;
            }

            // 更新按钮状态
            document.getElementById('btnLiveStackStart').disabled = false;
            document.getElementById('btnLiveStackStop').disabled = true;

            document.getElementById('liveStackStatus').textContent =
                '叠加: 已停止 (' + liveStackFrameCount + '帧)';
        }

